const curveSel = $('#dc-curve');
const pSel = $('#dc-p');
const out = $('#dc-out');
if(!curveSel || !pSel || !out) return;

// hand-curated (a_p, reduction) tables for illustration
const DATA = {
  '11a': {
    name:'E/ℚ: y² + y = x³ − x² − 10x − 20', cond: 11,
    primes: [
      {p:2, red:'good', a:-2},
      {p:3, red:'good', a:-1},
      {p:5, red:'good', a:1},
      {p:7, red:'good', a:-2},
      {p:11, red:'mult', a:1},  // split multiplicative
      {p:13, red:'good', a:4},
      {p:17, red:'good', a:-2},
      {p:19, red:'good', a:0},
      {p:23, red:'good', a:-1},
    ]
  },
  '37a': {
    name:'E/ℚ: y² + y = x³ − x', cond: 37,
    primes: [
      {p:2, red:'good', a:-2},
      {p:3, red:'good', a:-3},
      {p:5, red:'good', a:-2},
      {p:7, red:'good', a:-1},
      {p:11, red:'good', a:-5},
      {p:13, red:'good', a:-2},
      {p:17, red:'good', a:0},
      {p:19, red:'good', a:0},
      {p:23, red:'good', a:2},
      {p:29, red:'good', a:6},
      {p:31, red:'good', a:-4},
      {p:37, red:'mult', a:1}, // split multiplicative
    ]
  },
  'cm': {
    name:'E/ℚ: y² = x³ − x', cond: 32,
    primes: [
      {p:2, red:'add', a:0},
      {p:3, red:'good', a:0},
      {p:5, red:'good', a:-2},
      {p:7, red:'good', a:0},
      {p:11, red:'good', a:0},
      {p:13, red:'good', a:6},
      {p:17, red:'good', a:2},
      {p:19, red:'good', a:0},
      {p:23, red:'good', a:0},
      {p:29, red:'good', a:-10},
      {p:31, red:'good', a:0},
    ]
  }
};

function fillPrimes(){
  const key = curveSel.value;
  const ps = DATA[key].primes;
  pSel.innerHTML = '';
  ps.forEach(p => {
    const o = document.createElement('option');
    o.value = p.p;
    o.textContent = 'p = ' + p.p + ' (' + p.red + ')';
    pSel.appendChild(o);
  });
  render();
}

function render(){
  const key = curveSel.value;
  const C = DATA[key];
  const p = parseInt(pSel.value, 10);
  const row = C.primes.find(r => r.p === p);
  if(!row){ out.textContent = ''; return; }
  let factor, meaning;
  if(row.red === 'good'){
    factor = `(1 − (${row.a})·${p}^(−s) + ${p}·${p}^(−2s))^(−1)`;
    meaning = `good reduction → degree-2 local factor; Hasse: |a_p| ≤ 2√p = ${(2*Math.sqrt(p)).toFixed(3)}`;
  } else if(row.red === 'mult'){
    factor = `(1 − (${row.a})·${p}^(−s))^(−1)`;
    meaning = `multiplicative reduction (node) → degree-1 factor; a_p = ±1 records split vs non-split`;
  } else {
    factor = `1`;
    meaning = `additive reduction (cusp) → local factor is 1 (trivial contribution)`;
  }
  out.textContent =
    C.name + '\n' +
    'conductor N = ' + C.cond + '\n' +
    'prime p = ' + p + '   reduction: ' + row.red + '   a_p = ' + row.a + '\n\n' +
    'L_p(s) = ' + factor + '\n\n' +
    meaning;
}

curveSel.addEventListener('change', fillPrimes);
pSel.addEventListener('change', render);
fillPrimes();

const svg = $('#ec-svg');
const sInp = $('#ec-s');
const sV = $('#ec-sv');
if(!svg || !sInp) return;

// same CM curve data — compute a_n from a_p via multiplicativity + recursion
function apCurve(p){
  if(p===2) return 0; // additive
  if(p%4 === 3) return 0;
  for(let a=1;a*a<=p;a+=2){
    const b2 = p-a*a; const b = Math.round(Math.sqrt(b2));
    if(b*b===b2){ let aa=a; if(aa%4===3) aa=-aa; return 2*aa; }
  }
  return 0;
}
function isPrime(n){ if(n<2) return false; for(let k=2;k*k<=n;k++){ if(n%k===0) return false; } return true; }
const PR = [];
for(let n=2;n<=80;n++) if(isPrime(n)) PR.push(n);

// build a_n up to N=80
const N = 80;
const an = new Array(N+1).fill(0);
an[1] = 1;
// For each prime p compute a_{p^k} via a_{p^(k+1)} = a_p * a_{p^k} − p * a_{p^(k-1)} (good), or a_{p^k}=a_p^k (mult), or 0 (additive).
function apkTable(p){
  const out = {1: 1};
  let pk = p;
  if(p===2){ // additive reduction
    while(pk<=N){ out[pk]=0; pk*=p; }
    return out;
  }
  const ap = apCurve(p);
  out[p] = ap;
  let prev = 1, cur = ap; pk = p*p;
  while(pk<=N){
    const next = ap*cur - p*prev;
    out[pk] = next;
    prev = cur; cur = next; pk *= p;
  }
  return out;
}
const tbl = {};
PR.forEach(p => { tbl[p] = apkTable(p); });
// factor n, a_n = prod a_{p^{k}}
function factor(n){
  const f = {};
  for(const p of PR){ if(p*p>n && n>1) break; while(n%p===0){ f[p]=(f[p]||0)+1; n/=p; } if(n===1) break; }
  if(n>1) f[n] = 1;
  return f;
}
for(let n=2;n<=N;n++){
  const f = factor(n);
  let prod = 1;
  let ok = true;
  for(const p in f){
    const pk = Math.pow(parseInt(p,10), f[p]);
    const v = tbl[p] && tbl[p][pk];
    if(v === undefined){ ok = false; break; }
    prod *= v;
  }
  an[n] = ok ? prod : 0;
}

// compute series partial sum S_N(s) and Euler partial prod E_P(s) for P ranging over primes up to 60
function partials(s){
  const S = []; let sum = 0;
  for(let n=1;n<=N;n++){ sum += an[n]/Math.pow(n, s); S.push(sum); }
  const Pmax = 60;
  const E = []; let prod = 1;
  for(const p of PR){
    if(p>Pmax) break;
    let Lp;
    if(p===2){ Lp = 1; } // additive
    else {
      const ap = apCurve(p);
      Lp = 1 / (1 - ap*Math.pow(p,-s) + p*Math.pow(p,-2*s));
    }
    prod *= Lp;
    E.push({p, val: prod});
  }
  return {S, E};
}

function draw(){
  svg.innerHTML = '';
  const s = parseFloat(sInp.value);
  sV.textContent = 's = ' + s.toFixed(2);
  const {S, E} = partials(s);
  // shared y range
  const allv = [...S, ...E.map(x=>x.val)];
  const ymin = Math.min(...allv);
  const ymax = Math.max(...allv);
  const pad = 0.05*(ymax-ymin || 1);
  const yLo = ymin - pad, yHi = ymax + pad;

  const W = 640, H = 240, padL = 46, padR = 16, padT = 14, padB = 34;
  const toX = i => padL + (i/(N-1))*(W-padL-padR);
  const toY = v => H - padB - (v-yLo)/(yHi-yLo)*(H-padT-padB);

  // axes
  svg.appendChild(SVG('line',{x1:padL,y1:H-padB,x2:W-padR,y2:H-padB,stroke:'var(--mute)'}));
  svg.appendChild(SVG('line',{x1:padL,y1:padT,x2:padL,y2:H-padB,stroke:'var(--mute)'}));
  // y ticks
  for(let k=0;k<=4;k++){
    const v = yLo + k*(yHi-yLo)/4;
    const y = toY(v);
    svg.appendChild(SVG('line',{x1:padL-3,y1:y,x2:padL,y2:y,stroke:'var(--mute)'}));
    const t = SVG('text',{x:padL-6,y:y+4,'text-anchor':'end','font-size':10,fill:'var(--mute)'});
    t.textContent = v.toFixed(3); svg.appendChild(t);
  }

  // partial-sum curve (cyan) — indexed by n
  let d1 = '';
  S.forEach((v, i) => {
    const x = toX(i), y = toY(v);
    d1 += (i===0?'M':'L') + x.toFixed(1) + ' ' + y.toFixed(1) + ' ';
  });
  svg.appendChild(SVG('path',{d:d1,fill:'none',stroke:'var(--cyan)','stroke-width':1.8}));

  // partial-Euler points (yellow) — each at prime position p on same x-axis scaled to index n=p
  E.forEach(pt => {
    const i = Math.min(pt.p - 1, N - 1);
    const x = toX(i), y = toY(pt.val);
    svg.appendChild(SVG('circle',{cx:x,cy:y,r:3,fill:'var(--yellow)'}));
  });
  // connect Euler points with a dashed line
  let d2 = '';
  E.forEach((pt, i) => {
    const x = toX(Math.min(pt.p - 1, N - 1));
    const y = toY(pt.val);
    d2 += (i===0?'M':'L') + x.toFixed(1) + ' ' + y.toFixed(1) + ' ';
  });
  svg.appendChild(SVG('path',{d:d2,fill:'none',stroke:'var(--yellow)','stroke-width':1.4,'stroke-dasharray':'4 3'}));

  // legend
  const g1 = SVG('g'); svg.appendChild(g1);
  svg.appendChild(SVG('line',{x1:W-180,y1:padT+10,x2:W-160,y2:padT+10,stroke:'var(--cyan)','stroke-width':2}));
  let ttt = SVG('text',{x:W-155,y:padT+14,'font-size':11,fill:'var(--ink)'});
  ttt.textContent = 'partial sum  Σ a_n/n^s';
  svg.appendChild(ttt);
  svg.appendChild(SVG('line',{x1:W-180,y1:padT+28,x2:W-160,y2:padT+28,stroke:'var(--yellow)','stroke-width':2,'stroke-dasharray':'4 3'}));
  ttt = SVG('text',{x:W-155,y:padT+32,'font-size':11,fill:'var(--ink)'});
  ttt.textContent = 'partial Euler  ∏_{p ≤ P} L_p(s)';
  svg.appendChild(ttt);

  const xl = SVG('text',{x:W-padR,y:H-10,'text-anchor':'end','font-size':11,fill:'var(--mute)'});
  xl.textContent = 'index (n for sum, p for Euler)';
  svg.appendChild(xl);
}
sInp.addEventListener('input', draw);
draw();

