const kSel = $('#hk-k'), pSel = $('#hk-p'), apIn = $('#hk-ap'), out = $('#hk-out'), svg = $('#hk-svg');
if(!kSel || !pSel || !apIn) return;
function run(){
  const k = parseInt(kSel.value, 10);
  const p = parseInt(pSel.value, 10);
  const ap = parseFloat(apIn.value);
  const pw = Math.pow(p, k-1);
  const A = [1, ap];
  for(let j=2;j<=8;j++){
    A.push(ap*A[j-1] - pw*A[j-2]);
  }
  out.textContent =
    `L_p(s)⁻¹ = 1 − ${ap}·${p}^(−s) + ${p}^${k-1}·${p}^(−2s)\n` +
    `         = 1 − ${ap}·${p}^(−s) + ${pw}·${p}^(−2s)\n\n` +
    'j   p^j         a_{p^j}\n' +
    A.map((v,j)=>`${j}   ${String(Math.pow(p,j)).padStart(7,' ')}    ${v}`).join('\n');

  // draw bar chart
  svg.innerHTML = '';
  const W = 640, H = 220, padL = 40, padR = 14, padT = 14, padB = 34;
  const n = A.length;
  const maxAbs = Math.max(...A.map(v=>Math.abs(v)), 1);
  const midY = padT + (H-padT-padB)/2;
  const barW = (W-padL-padR)/n * 0.55;
  const step = (W-padL-padR)/n;
  svg.appendChild(SVG('line',{x1:padL,y1:midY,x2:W-padR,y2:midY,stroke:'var(--mute)'}));
  A.forEach((v, j) => {
    const x = padL + step*(j+0.5) - barW/2;
    const h = v === 0 ? 2 : Math.abs(v)/maxAbs * (H-padT-padB)/2;
    const y = v >= 0 ? midY - h : midY;
